package com.pos;
import javax.swing.*; import java.awt.*;
public class StockOperationsPanel extends JPanel { private final UserSession s; private final QueryTableModel m=new QueryTableModel(); private final JTable t=new JTable(m); private final JTextField adjustProduct=new JTextField(5),transferProduct=new JTextField(5),location=new JTextField("1",5),quantity=new JTextField(7),reason=new JTextField(18),from=new JTextField("1",5),to=new JTextField("2",5),transferQty=new JTextField(7),notes=new JTextField(18);
 public StockOperationsPanel(UserSession s){super(new BorderLayout(8,8));this.s=s;JPanel h=new JPanel(new BorderLayout());h.add(UIUtils.title("Stock Adjustments and Transfers"),BorderLayout.WEST);JButton refresh=new JButton("Refresh Movement History");h.add(refresh,BorderLayout.EAST);add(h,BorderLayout.NORTH);add(new JScrollPane(t),BorderLayout.CENTER);JPanel south=new JPanel(new GridLayout(2,1));JPanel adj=new JPanel();adj.setBorder(BorderFactory.createTitledBorder("Stock Adjustment"));adj.add(new JLabel("Product ID"));adj.add(adjustProduct);adj.add(new JLabel("Location"));adj.add(location);adj.add(new JLabel("Quantity +/-"));adj.add(quantity);adj.add(new JLabel("Reason"));adj.add(reason);JButton post=new JButton("Post Adjustment");adj.add(post);JPanel tr=new JPanel();tr.setBorder(BorderFactory.createTitledBorder("Location Transfer"));tr.add(new JLabel("Product ID"));tr.add(transferProduct);tr.add(new JLabel("From"));tr.add(from);tr.add(new JLabel("To"));tr.add(to);tr.add(new JLabel("Qty"));tr.add(transferQty);tr.add(new JLabel("Notes"));tr.add(notes);JButton move=new JButton("Post Transfer");tr.add(move);south.add(adj);south.add(tr);add(south,BorderLayout.SOUTH);refresh.addActionListener(e->load());post.addActionListener(e->adjust());move.addActionListener(e->transfer());load();}
 private void load(){try{m.load("SELECT m.movement_id,p.product_name,m.movement_type,m.reference_table,m.reference_id,m.quantity_change,m.remarks,m.created_at FROM stock_movements m JOIN products p ON p.product_id=m.product_id ORDER BY m.movement_id DESC");}catch(Exception e){UIUtils.error(this,e);}}
 private void adjust(){try{POSService.postAdjustment(Integer.parseInt(adjustProduct.getText()),Integer.parseInt(location.getText()),Double.parseDouble(quantity.getText()),reason.getText(),s.userId);Audit.log(s,"STOCK_ADJUSTMENT",adjustProduct.getText());load();UIUtils.info(this,"Stock adjustment posted.");}catch(Exception e){UIUtils.error(this,e);}}
 private void transfer(){try{POSService.postTransfer(Integer.parseInt(transferProduct.getText()),Integer.parseInt(from.getText()),Integer.parseInt(to.getText()),Double.parseDouble(transferQty.getText()),notes.getText(),s.userId);Audit.log(s,"STOCK_TRANSFER",transferProduct.getText());load();UIUtils.info(this,"Stock transfer posted.");}catch(Exception e){UIUtils.error(this,e);}}
}
